#include "core_internal.h"
#include "sloph/context.h"

#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct { const char **names; SlophCoreType **types; size_t count; } Env;
typedef struct {
    SlophContext *ctx; SlophCoreUnit *unit;
    const char **all_binders; size_t binder_count, binder_cap;
    SlophCoreType **temps; size_t temp_count, temp_cap;
} Check;

static SlophSpan sp(SlophCoreSpan s) { SlophSpan r = {s.start, s.end}; return r; }
static SlophStatus fail(Check *c, const char *code, const char *message, SlophCoreSpan s) {
    SlophStatus r = sloph_context_add_diagnostic(c->ctx, code, "validate", message, sp(s));
    return r == SLOPH_STATUS_OK ? SLOPH_STATUS_INVALID_ARGUMENT : r;
}
static SlophStatus fail_details(Check*c,const char*code,const char*message,const char*details,SlophCoreSpan s){SlophStatus r=sloph_context_add_diagnostic_full(c->ctx,code,"validate",message,details,sp(s),SLOPH_SEVERITY_ERROR);return r==SLOPH_STATUS_OK?SLOPH_STATUS_INVALID_ARGUMENT:r;}
static void text_add(char*out,size_t cap,size_t*len,const char*s){size_t n=strlen(s);if(*len<cap-1u){if(n>cap-1u-*len)n=cap-1u-*len;memcpy(out+*len,s,n);*len+=n;out[*len]=0;}}
static void type_text(const SlophCoreType*t,char*out,size_t cap,size_t*len){size_t i;switch(t->kind){case SLOPH_TYPE_INT:text_add(out,cap,len,"Int");break;case SLOPH_TYPE_BYTES:text_add(out,cap,len,"Bytes");break;case SLOPH_TYPE_NAMED:text_add(out,cap,len,"(named ");text_add(out,cap,len,t->as.name);text_add(out,cap,len,")");break;case SLOPH_TYPE_VARIABLE:text_add(out,cap,len,"(var ");text_add(out,cap,len,t->as.name);text_add(out,cap,len,")");break;case SLOPH_TYPE_APPLIED:text_add(out,cap,len,"(apply ");text_add(out,cap,len,t->as.applied.constructor);for(i=0;i<t->as.applied.count;++i){text_add(out,cap,len," ");type_text(t->as.applied.items[i],out,cap,len);}text_add(out,cap,len,")");break;case SLOPH_TYPE_FUNCTION:text_add(out,cap,len,"(fn ");if(strcmp(t->as.function.mode,"own")){text_add(out,cap,len,t->as.function.mode);text_add(out,cap,len," ");}type_text(t->as.function.parameter,out,cap,len);text_add(out,cap,len," ");type_text(t->as.function.result,out,cap,len);text_add(out,cap,len,")");break;case SLOPH_TYPE_FORALL:text_add(out,cap,len,"(forall ");text_add(out,cap,len,t->as.forall.parameter);text_add(out,cap,len," ");type_text(t->as.forall.body,out,cap,len);text_add(out,cap,len,")");break;}}
static bool segment(const char *s, size_t n) {
    size_t i;
    if (!n || !((s[0]>='A'&&s[0]<='Z')||(s[0]>='a'&&s[0]<='z')||s[0]=='_')) return false;
    for (i=1;i<n;++i) if (!((s[i]>='A'&&s[i]<='Z')||(s[i]>='a'&&s[i]<='z')||(s[i]>='0'&&s[i]<='9')||s[i]=='_')) return false;
    return true;
}
static bool local_id(const char *s) { return segment(s, strlen(s)); }
static bool global_id(const char *s) {
    const char *p=s; size_t n=0;
    for (;;) { const char *q=strstr(p,"::"); size_t z=q?(size_t)(q-p):strlen(p); if(!segment(p,z))return false; ++n; if(!q)break; p=q+2; }
    return n>=2;
}
static SlophCoreEnum *enum_find(Check *c,const char *n) { size_t i; for(i=0;i<c->unit->type_count;++i)if(!strcmp(c->unit->types[i].name,n))return &c->unit->types[i]; return NULL; }
static SlophCoreDefinition *def_find(Check *c,const char *n) { size_t i; for(i=0;i<c->unit->definition_count;++i)if(!strcmp(c->unit->definitions[i].name,n))return &c->unit->definitions[i]; return NULL; }
static SlophCoreConstructor *con_find(Check *c,const char *n,SlophCoreEnum **e) { size_t i,j; for(i=0;i<c->unit->type_count;++i)for(j=0;j<c->unit->types[i].constructor_count;++j)if(!strcmp(c->unit->types[i].constructors[j].name,n)){*e=&c->unit->types[i];return &c->unit->types[i].constructors[j];} return NULL; }
static bool equal(const SlophCoreType *a,const SlophCoreType *b) {
    size_t i; if(!a||!b||a->kind!=b->kind)return false;
    switch(a->kind){
    case SLOPH_TYPE_INT:case SLOPH_TYPE_BYTES:return true;
    case SLOPH_TYPE_NAMED:case SLOPH_TYPE_VARIABLE:return !strcmp(a->as.name,b->as.name);
    case SLOPH_TYPE_APPLIED:if(strcmp(a->as.applied.constructor,b->as.applied.constructor)||a->as.applied.count!=b->as.applied.count)return false;for(i=0;i<a->as.applied.count;++i)if(!equal(a->as.applied.items[i],b->as.applied.items[i]))return false;return true;
    case SLOPH_TYPE_FUNCTION:return !strcmp(a->as.function.mode,b->as.function.mode)&&equal(a->as.function.parameter,b->as.function.parameter)&&equal(a->as.function.result,b->as.function.result);
    case SLOPH_TYPE_FORALL:return !strcmp(a->as.forall.parameter,b->as.forall.parameter)&&equal(a->as.forall.body,b->as.forall.body);
    } return false;
}
static char *dupstr(const char *s){size_t n=strlen(s)+1u;char *r=(char*)malloc(n);if(r)memcpy(r,s,n);return r;}
static SlophCoreType *clone_sub(const SlophCoreType *t,const char *name,const SlophCoreType *replacement) {
    SlophCoreType *r; size_t i;
    if(t->kind==SLOPH_TYPE_VARIABLE&&!strcmp(t->as.name,name))t=replacement;
    r=(SlophCoreType*)calloc(1u,sizeof(*r));if(!r)return NULL;r->kind=t->kind;
    switch(t->kind){
    case SLOPH_TYPE_INT:case SLOPH_TYPE_BYTES:break;
    case SLOPH_TYPE_NAMED:case SLOPH_TYPE_VARIABLE:r->as.name=dupstr(t->as.name);if(!r->as.name)goto bad;break;
    case SLOPH_TYPE_APPLIED:r->as.applied.constructor=dupstr(t->as.applied.constructor);r->as.applied.count=t->as.applied.count;r->as.applied.items=(SlophCoreType**)calloc(t->as.applied.count,sizeof(*r->as.applied.items));if(!r->as.applied.constructor||(t->as.applied.count&&!r->as.applied.items))goto bad;for(i=0;i<t->as.applied.count;++i)if(!(r->as.applied.items[i]=clone_sub(t->as.applied.items[i],name,replacement)))goto bad;break;
    case SLOPH_TYPE_FUNCTION:r->as.function.mode=dupstr(t->as.function.mode);r->as.function.parameter=clone_sub(t->as.function.parameter,name,replacement);r->as.function.result=clone_sub(t->as.function.result,name,replacement);if(!r->as.function.mode||!r->as.function.parameter||!r->as.function.result)goto bad;break;
    case SLOPH_TYPE_FORALL:r->as.forall.parameter=dupstr(t->as.forall.parameter);r->as.forall.body=clone_sub(t->as.forall.body,!strcmp(t->as.forall.parameter,name)?"":name,replacement);if(!r->as.forall.parameter||!r->as.forall.body)goto bad;break;
    }return r;
bad:sloph_core_type_destroy(r);return NULL;
}
static SlophStatus temp(Check*c,SlophCoreType*t,SlophCoreType**out){
    if(!t)return SLOPH_STATUS_OUT_OF_MEMORY;
    if(c->temp_count==c->temp_cap){size_t z=c->temp_cap?c->temp_cap*2u:16u;SlophCoreType**p=(SlophCoreType**)realloc(c->temps,z*sizeof(*p));if(!p){sloph_core_type_destroy(t);return SLOPH_STATUS_OUT_OF_MEMORY;}c->temps=p;c->temp_cap=z;}
    c->temps[c->temp_count++]=t;*out=t;return SLOPH_STATUS_OK;
}
static bool scoped(const char **v,size_t n,const char*s){size_t i;for(i=0;i<n;++i)if(!strcmp(v[i],s))return true;return false;}
static SlophStatus wf(Check*c,SlophCoreType*t,SlophCoreSpan s,const char**vars,size_t n){
    size_t i;SlophCoreEnum*e;SlophStatus r;
    switch(t->kind){
    case SLOPH_TYPE_INT:return SLOPH_STATUS_OK;
    case SLOPH_TYPE_BYTES:return c->unit->version?SLOPH_STATUS_OK:fail(c,"core.validate.bytes_version","Bytes requires Core version 1 or later",s);
    case SLOPH_TYPE_NAMED:e=enum_find(c,t->as.name);if(!e)return fail(c,"core.validate.unknown_type","unknown nominal type",s);return e->type_parameter_count?fail(c,"core.validate.type_arity","generic type requires type arguments",s):SLOPH_STATUS_OK;
    case SLOPH_TYPE_VARIABLE:if(scoped(vars,n,t->as.name))return SLOPH_STATUS_OK;{char message[256],details[256];(void)snprintf(message,sizeof(message),"free type variable '%s'",t->as.name);(void)snprintf(details,sizeof(details),"{\"variable\":\"%s\"}",t->as.name);return fail_details(c,"core.validate.free_type_variable",message,details,s);}
    case SLOPH_TYPE_APPLIED:e=enum_find(c,t->as.applied.constructor);if(!e)return fail(c,"core.validate.unknown_type","unknown nominal type",s);if(e->type_parameter_count!=t->as.applied.count)return fail(c,"core.validate.type_arity","type has wrong argument count",s);for(i=0;i<t->as.applied.count;++i)if((r=wf(c,t->as.applied.items[i],s,vars,n))!=SLOPH_STATUS_OK)return r;return SLOPH_STATUS_OK;
    case SLOPH_TYPE_FUNCTION:if(strcmp(t->as.function.mode,"own")&&strcmp(t->as.function.mode,"borrow"))return fail(c,"core.validate.parameter_mode","parameter mode must be own or borrow",s);if(strcmp(t->as.function.mode,"own")&&c->unit->version!=3)return fail(c,"core.validate.parameter_mode_version","borrow parameters require Core version 3",s);r=wf(c,t->as.function.parameter,s,vars,n);return r==SLOPH_STATUS_OK?wf(c,t->as.function.result,s,vars,n):r;
    case SLOPH_TYPE_FORALL:{const char**nv;if(c->unit->version<2)return fail(c,"core.validate.generic_version","universal types require Core version 2 or later",s);if(scoped(vars,n,t->as.forall.parameter))return fail(c,"core.validate.duplicate_type_parameter","duplicate type parameter",s);nv=(const char**)malloc((n+1u)*sizeof(*nv));if(!nv)return SLOPH_STATUS_OUT_OF_MEMORY;if(n)memcpy(nv,vars,n*sizeof(*nv));nv[n]=t->as.forall.parameter;r=wf(c,t->as.forall.body,s,nv,n+1u);free(nv);return r;}
    }return fail(c,"core.validate.type_form","unknown Core type representation",s);
}
static SlophCoreType *env_get(Env e,const char*n){size_t i=e.count;while(i){--i;if(!strcmp(e.names[i],n))return e.types[i];}return NULL;}
static SlophStatus binder(Check*c,SlophCoreBinder*b,const char**vars,size_t n){size_t i;if(!local_id(b->name))return fail(c,"core.validate.local_identity","invalid local identity",b->span);for(i=0;i<c->binder_count;++i)if(!strcmp(c->all_binders[i],b->name))return fail(c,"core.validate.duplicate_local","local binder is reused in one definition",b->span);if(c->binder_count==c->binder_cap){size_t z=c->binder_cap?c->binder_cap*2u:16u;const char**p=(const char**)realloc(c->all_binders,z*sizeof(*p));if(!p)return SLOPH_STATUS_OUT_OF_MEMORY;c->all_binders=p;c->binder_cap=z;}c->all_binders[c->binder_count++]=b->name;return wf(c,b->type,b->span,vars,n);}
static SlophCoreType tint={.kind=SLOPH_TYPE_INT},tbytes={.kind=SLOPH_TYPE_BYTES},tbool={.kind=SLOPH_TYPE_NAMED,.as.name="sloph::Bool"},tunit={.kind=SLOPH_TYPE_NAMED,.as.name="sloph::Unit"};
static bool primitive(const char*n,int v,SlophCoreType***p,size_t*c,SlophCoreType**r){static SlophCoreType*i2[]={&tint,&tint},*i1[]={&tint},*b1[]={&tbytes};if(!strcmp(n,"int.add")||!strcmp(n,"int.sub")||!strcmp(n,"int.mul")){*p=i2;*c=2;*r=&tint;return true;}if(!v)return false;if(!strcmp(n,"int.equal")||!strcmp(n,"int.less")){*p=i2;*c=2;*r=&tbool;return true;}if(!strcmp(n,"int.to_bytes")){*p=i1;*c=1;*r=&tbytes;return true;}if(!strcmp(n,"bytes.length")){*p=b1;*c=1;*r=&tint;return true;}if(!strcmp(n,"runtime.trap")){*p=b1;*c=1;*r=&tunit;return true;}return false;}
static SlophStatus infer(Check*,SlophCoreExpr*,Env,const char**,size_t,SlophCoreType**);
