    case SLOPH_EXPR_LAM:
      if(x->as.lam.binder.is_type){const char**nv;SlophCoreType*t;if(c->unit->version<2)return fail(c,"core.validate.generic_version","type abstractions require Core version 2 or later",x->span);nv=(const char**)malloc((n+1u)*sizeof(*nv));if(!nv)return SLOPH_STATUS_OUT_OF_MEMORY;if(n)memcpy(nv,vars,n*sizeof(*nv));nv[n]=x->as.lam.binder.name;r=infer(c,x->as.lam.body,e,nv,n+1u,&a);free(nv);if(r!=SLOPH_STATUS_OK)return r;t=(SlophCoreType*)calloc(1,sizeof(*t));if(!t)return SLOPH_STATUS_OUT_OF_MEMORY;t->kind=SLOPH_TYPE_FORALL;t->as.forall.parameter=dupstr(x->as.lam.binder.name);t->as.forall.body=clone_sub(a,"",a);if(!t->as.forall.parameter||!t->as.forall.body){sloph_core_type_destroy(t);return SLOPH_STATUS_OUT_OF_MEMORY;}return temp(c,t,out);}
      else {const char**ns;SlophCoreType**ts;Env ne;SlophCoreType*t;r=binder(c,&x->as.lam.binder,vars,n);if(r!=SLOPH_STATUS_OK)return r;ns=(const char**)malloc((e.count+1)*sizeof(*ns));ts=(SlophCoreType**)malloc((e.count+1)*sizeof(*ts));if(!ns||!ts){free(ns);free(ts);return SLOPH_STATUS_OUT_OF_MEMORY;}if(e.count){memcpy(ns,e.names,e.count*sizeof(*ns));memcpy(ts,e.types,e.count*sizeof(*ts));}ns[e.count]=x->as.lam.binder.name;ts[e.count]=x->as.lam.binder.type;ne=(Env){ns,ts,e.count+1};r=infer(c,x->as.lam.body,ne,vars,n,&a);free(ns);free(ts);if(r!=SLOPH_STATUS_OK)return r;t=(SlophCoreType*)calloc(1,sizeof(*t));if(!t)return SLOPH_STATUS_OUT_OF_MEMORY;t->kind=SLOPH_TYPE_FUNCTION;t->as.function.mode=dupstr(x->as.lam.binder.mode);t->as.function.parameter=clone_sub(x->as.lam.binder.type,"",x->as.lam.binder.type);t->as.function.result=clone_sub(a,"",a);if(!t->as.function.mode||!t->as.function.parameter||!t->as.function.result){sloph_core_type_destroy(t);return SLOPH_STATUS_OUT_OF_MEMORY;}return temp(c,t,out);}
    case SLOPH_EXPR_APP:r=infer(c,x->as.app.function,e,vars,n,&a);if(r!=SLOPH_STATUS_OK)return r;if(x->as.app.argument->kind==SLOPH_EXPR_TYPE){if(a->kind!=SLOPH_TYPE_FORALL)return fail(c,"core.validate.not_polymorphic","type application target is not polymorphic",x->as.app.function->span);r=wf(c,x->as.app.argument->as.type,x->as.app.argument->span,vars,n);if(r!=SLOPH_STATUS_OK)return r;return temp(c,clone_sub(a->as.forall.body,a->as.forall.parameter,x->as.app.argument->as.type),out);}r=infer(c,x->as.app.argument,e,vars,n,&b);if(r!=SLOPH_STATUS_OK)return r;if(a->kind!=SLOPH_TYPE_FUNCTION){char message[1200]={0};size_t z=0;text_add(message,sizeof(message),&z,"application target has non-function type ");type_text(a,message,sizeof(message),&z);return fail(c,"core.validate.not_function",message,x->as.app.function->span);}if(!equal(b,a->as.function.parameter))return fail(c,"core.validate.type_mismatch","expected and actual types differ",x->as.app.argument->span);return temp(c,clone_sub(a->as.function.result,"",a->as.function.result),out);
    case SLOPH_EXPR_LET:{const char**ns;SlophCoreType**ts;Env ne;r=infer(c,x->as.let.value,e,vars,n,&a);if(r!=SLOPH_STATUS_OK)return r;r=binder(c,&x->as.let.binder,vars,n);if(r!=SLOPH_STATUS_OK)return r;if(!equal(a,x->as.let.binder.type))return fail(c,"core.validate.type_mismatch","expected and actual types differ",x->as.let.value->span);ns=(const char**)malloc((e.count+1)*sizeof(*ns));ts=(SlophCoreType**)malloc((e.count+1)*sizeof(*ts));if(!ns||!ts){free(ns);free(ts);return SLOPH_STATUS_OUT_OF_MEMORY;}if(e.count){memcpy(ns,e.names,e.count*sizeof(*ns));memcpy(ts,e.types,e.count*sizeof(*ts));}ns[e.count]=x->as.let.binder.name;ts[e.count]=x->as.let.binder.type;ne=(Env){ns,ts,e.count+1};r=infer(c,x->as.let.body,ne,vars,n,out);free(ns);free(ts);return r;}
    case SLOPH_EXPR_PRIM:{SlophCoreType**ps=NULL,*result=NULL;size_t count=0;if(!primitive(x->as.prim.name,c->unit->version,&ps,&count,&result)){size_t j;for(j=0;j<c->unit->foreign_binding_count;++j)if(strcmp(c->unit->foreign_bindings[j].adapter,"unavailable")&& !strcmp(c->unit->foreign_bindings[j].identity,x->as.prim.name)){ps=c->unit->foreign_bindings[j].parameters;count=c->unit->foreign_bindings[j].parameter_count;result=c->unit->foreign_bindings[j].result;break;}}if(!result)return fail(c,"core.validate.unknown_primitive","unknown primitive",x->span);if(count!=x->as.prim.count)return fail(c,"core.validate.primitive_arity","primitive has wrong argument count",x->span);for(i=0;i<count;++i){r=infer(c,x->as.prim.items[i],e,vars,n,&a);if(r!=SLOPH_STATUS_OK)return r;if(!equal(a,ps[i]))return fail(c,"core.validate.type_mismatch","expected and actual types differ",x->as.prim.items[i]->span);}*out=result;return SLOPH_STATUS_OK;}
